mapper.update:
UPDATE tb_ai_quota_daily_usage
SET
    used_count = used_count + 1,
    updated_at = NOW()
WHERE user_id = #{userId}
  AND usage_date = #{usageDate}
  AND is_active = 1
  AND used_count < #{effectiveLimit}

mapper.select:
SELECT COALESCE(SUM(amount), 0)
FROM tb_ai_quota_grant
WHERE user_id = #{userId}
  AND grant_date = #{grantDate}
  AND is_active = 1
